import{j as e,L as i}from"./index-ixzp0WJG.js";/* empty css               */const a=()=>e.jsxs("div",{children:[e.jsx(i,{to:"/levels",className:"backButton level-theme-grief",children:"Back"}),e.jsxs("div",{className:"aLevelContainer level-theme-grief",children:[e.jsx("h1",{children:"Grief"}),e.jsx("p",{children:"Feels like: sadness, loss, despondency."}),e.jsx("p",{children:"Manifests as: mourning, bereavement, remorse about the past."}),e.jsx("p",{children:"Most people have experienced it for periods of time, but those who remain at this level live a life of constant regret and depression, which makes them feel like a loser and accept failure as part of their lifestyle. This often results in the loss of jobs, friends, family, opportunities, as well as money and health."}),e.jsx("p",{children:"In grief, one sees sadness everywhere—everything seems miserable and grim."}),e.jsx("p",{children:"Though grief is the cemetery of life, it has more energy to it than apathy. Thus, when traumatised apathetic patients begin to cry, they are getting better—for once they start to cry, they will eat again."}),e.jsx("p",{children:"The universality of the experience is due to the structure and nature of the ego, which misperceives the source of happiness as external or emotional and imbues it with specialness. In reality, the only source of happiness is from within, and its mechanism is intrapsychic and internal."}),e.jsx("p",{children:"Society collectively assumes that certain conditions, objects, or qualities are valuable, while in reality, the value is always in the eyes of the beholder and is never intrinsic to the desired object or person itself."}),e.jsx("p",{children:"It is possible to evolve spiritually so as to become relatively immune to grief—to realise that the source of happiness originates from within and is not dependent on externals."}),e.jsx("p",{children:"If the source of happiness is acquired through ego mechanisms, objects, qualities, or relationships become overvalued by virtue of the mechanism of attachment."}),e.jsx("p",{children:"Fear of loss contributes to dependent attachments, as well as materiality or social attributes such as money and fame."}),e.jsx("p",{children:"A loss at first is an unwelcome event because it is disruptive and emotionally intrusive. The initial response may be shock, resentment, disbelief. Processing the crisis is helped by focusing on certain inner realities and transcending their limitations."}),e.jsx("p",{children:"Disruption of life by the unexpected also creates anxiety at the forced readjustment, which may require major decision-making. Suffering and emotional pain result largely from resistance to what is and what could be. Its cure lies in surrender, acceptance, and trust that everything that happens is for the highest good."}),e.jsx("p",{children:"The source of pain is not the belief system itself, but one's attachment to it and the inflation of its imaginary value. The inner processing of attachments is dependent on the exercise of the will, which alone has the power to surrender."}),e.jsx("p",{children:'Grief has to do with loss, and loss implies prior ownership and a special relationship. The idea of "mine" or "my" denotes a unique contextualisation by which a separate "I" is magically bonded, in fantasy, to an "it" or a "you", and thereby to some quality, possession, or person. For example, a watch is merely an object, but with the claim of ownership, it is now imbued with a unique, special quality called "mine".'}),e.jsx("p",{children:"The emotional charge can be loosened by realising that everything actually belongs to the universe at large. Ownership in human terms is a transitory specialness, and value and worth exist only in perception, conceptualisation, and legalities."})]})]});export{a as default};
